mapper.select:
SELECT id, room_id, sender_id, receiver_id, content, emoji, read_at, sent_at
FROM lucky_letters
WHERE id = #{id}

SELECT l.id, l.sender_id, sender.nickname AS sender_nickname, sender.profile_image_url AS sender_profile_image_url,
       l.receiver_id, receiver.nickname AS receiver_nickname, receiver.profile_image_url AS receiver_profile_image_url,
       l.content, l.emoji, l.read_at, l.sent_at,
       EXISTS(
           SELECT 1 FROM letter_favorites f
           WHERE f.letter_id = l.id AND f.user_id = #{viewerId}
       ) AS is_favorite
FROM lucky_letters l
JOIN users sender ON sender.id = l.sender_id
JOIN users receiver ON receiver.id = l.receiver_id
WHERE l.room_id = #{roomId}

    AND l.receiver_id = #{viewerId}


    AND l.sender_id = #{viewerId}

ORDER BY l.sent_at DESC

mapper.update:
UPDATE lucky_letters
SET read_at = #{readAt}
WHERE id = #{id}
  AND read_at IS NULL

mapper.select:
SELECT EXISTS(
    SELECT 1
    FROM letter_favorites
    WHERE letter_id = #{letterId}
      AND user_id = #{userId}
)

mapper.delete:
DELETE FROM letter_favorites
WHERE letter_id = #{letterId}
  AND user_id = #{userId}
